import { Form, Head, setLayoutProps } from "@inertiajs/react";
import { REGEXP_ONLY_DIGITS, REGEXP_ONLY_DIGITS_AND_CHARS } from "input-otp";
import { useMemo, useState } from "react";
import InputError from "@/components/input-error";
import { Button } from "@/components/ui/button";
import { toastFirstFormError } from "@/lib/form-errors";
import { InputOTP, InputOTPGroup, InputOTPSlot } from "@/components/ui/input-otp";
import { Spinner } from "@/components/ui/spinner";
import { OTP_MAX_LENGTH } from "@/hooks/use-two-factor-auth";
import { store } from "@/routes/two-factor/login";

const RECOVERY_CODE_LENGTH = 20;
const formatRecoveryCode = (value: string): string =>
  value.length > 10 ? `${value.slice(0, 10)}-${value.slice(10)}` : value;

const normalizeAuthenticationCode = (value: string): string => value.replace(/\D/g, "");
const normalizeRecoveryCode = (value: string): string => value.replace(/[^a-zA-Z0-9]/g, "");

export default function TwoFactorChallenge() {
  const [showRecoveryInput, setShowRecoveryInput] = useState<boolean>(false);
  const [code, setCode] = useState<string>("");
  const [recoveryCode, setRecoveryCode] = useState<string>("");

  const authConfigContent = useMemo<{
    title: string;
    description: string;
    toggleText: string;
  }>(() => {
    if (showRecoveryInput) {
      return {
        title: "Recovery code",
        description:
          "Please confirm access to your account by entering one of your emergency recovery codes.",
        toggleText: "login using an authentication code",
      };
    }

    return {
      title: "Authentication code",
      description: "Enter the authentication code provided by your authenticator application.",
      toggleText: "login using a recovery code",
    };
  }, [showRecoveryInput]);

  setLayoutProps({
    title: authConfigContent.title,
    description: authConfigContent.description,
  });

  const toggleRecoveryMode = (clearErrors: () => void): void => {
    setShowRecoveryInput(!showRecoveryInput);
    clearErrors();
    setCode("");
    setRecoveryCode("");
  };

  const formattedRecoveryCode = formatRecoveryCode(recoveryCode);

  const renderRecoverySlots = (startIndex: number, length: number) =>
    Array.from({ length }, (_, index) => (
      <InputOTPSlot key={startIndex + index} index={startIndex + index} />
    ));

  return (
    <>
      <Head title="Two-factor authentication" />

      <div className="flex flex-col gap-6">
        <Form
          action={store()}
          resetOnError
          resetOnSuccess={!showRecoveryInput}
          onError={(errors) => {
            toastFirstFormError(errors);

            if (showRecoveryInput) {
              setRecoveryCode("");

              return;
            }

            setCode("");
          }}
          className="flex flex-col gap-5"
        >
          {({ processing, errors, clearErrors }) => (
            <>
              {showRecoveryInput ? (
                <div className="flex flex-col items-center justify-center gap-3 text-center">
                  <input type="hidden" name="recovery_code" value={formattedRecoveryCode} />
                  <div className="flex w-full items-center justify-center">
                    <InputOTP
                      maxLength={RECOVERY_CODE_LENGTH}
                      value={recoveryCode}
                      onChange={(value) => setRecoveryCode(normalizeRecoveryCode(value))}
                      disabled={processing}
                      pattern={REGEXP_ONLY_DIGITS_AND_CHARS}
                      pasteTransformer={normalizeRecoveryCode}
                      autoFocus
                      containerClassName="flex flex-wrap justify-center gap-2"
                    >
                      <InputOTPGroup>
                        {renderRecoverySlots(0, RECOVERY_CODE_LENGTH / 2)}
                      </InputOTPGroup>
                      <InputOTPGroup>
                        {renderRecoverySlots(RECOVERY_CODE_LENGTH / 2, RECOVERY_CODE_LENGTH / 2)}
                      </InputOTPGroup>
                    </InputOTP>
                  </div>
                  <InputError message={errors.recovery_code} />
                </div>
              ) : (
                <div className="flex flex-col items-center justify-center gap-3 text-center">
                  <div className="flex w-full items-center justify-center">
                    <InputOTP
                      name="code"
                      maxLength={OTP_MAX_LENGTH}
                      value={code}
                      onChange={(value) => setCode(normalizeAuthenticationCode(value))}
                      disabled={processing}
                      pattern={REGEXP_ONLY_DIGITS}
                      pasteTransformer={normalizeAuthenticationCode}
                      autoFocus
                    >
                      <InputOTPGroup>
                        {Array.from({ length: OTP_MAX_LENGTH }, (_, index) => (
                          <InputOTPSlot key={index} index={index} />
                        ))}
                      </InputOTPGroup>
                    </InputOTP>
                  </div>
                  <InputError message={errors.code} />
                </div>
              )}

              <Button type="submit" className="w-full" disabled={processing}>
                {processing && <Spinner />}
                Continue
              </Button>

              <div className="text-center text-sm text-muted-foreground">
                <span>or you can </span>
                <button
                  type="button"
                  className="cursor-pointer text-foreground underline decoration-neutral-300 underline-offset-4 transition-colors hover:decoration-current dark:decoration-neutral-500"
                  onClick={() => toggleRecoveryMode(clearErrors)}
                >
                  {authConfigContent.toggleText}
                </button>
              </div>
            </>
          )}
        </Form>
      </div>
    </>
  );
}

TwoFactorChallenge.layout = {
  title: "Authentication code",
  description: "Enter the authentication code provided by your authenticator application.",
};
